/**
 * BSA §5324 smurfing pattern gate (31 USC §5324; 31 CFR §1020.320).
 *
 * Scenario #20 of guides/use-cases.md: an AccountHolder originates
 * 6+ payments ≤ USD 3,000 to 6+ distinct creditor PAs inside 24h,
 * totalling > USD 10,000 — the classic smurfing typology (cash
 * structuring through multiple agents). SAR-eligible REVIEW. The
 * corpus models the verdict as BLOCK with rejected_rule=
 * 'smurfing_pattern_sar_eligible' until Transaction gains a :review
 * status; the rule's signature stays correct, only the verdict
 * surface relaxes once the enum widens.
 *
 * Distinct from #19 (ctr_structuring), which is the single-CP
 * sub-CTR-band pattern (USD 5,000-9,999 splits). Smurfing here is
 * many small payments to many distinct counterparties — a different
 * pattern under the same anti-structuring statute.
 *
 * Reads `account_holder.recent_debits_24h[]` (synthesised by
 * AtomicFi.RuleEngine.build_payload/2 via
 * TransactionContext.list_recent_debits_for_account_holder/2). Each
 * debit row is the public Transaction shape — `amount` and
 * `creditor_payment_account_id` are the fields this rule walks.
 *
 * The same rule fires on:
 *   - corpus/zen_rules/smurfing_pattern_sar_eligible/  (hand-authored
 *     6-payment fixture; the auditor-walkable golden)
 *   - sharded SAML-D bulk corpora under tmp/corpus/sharded/saml-d/
 *     (gitignored; SAML-D senders whose `Laundering_type='Smurfing'`
 *     rows produce the same shape collide naturally onto this rule).
 */
export const handler = async (input) => {
  const SMURF_MAX = 3000;
  const SMURF_THRESHOLD_TOTAL = 10000;
  const SMURF_MIN_COUNT = 6;
  const SMURF_MIN_DISTINCT_CP = 6;

  const txAmount = (input.transaction && input.transaction.amount) || 0;
  if (typeof txAmount !== 'number' || txAmount > SMURF_MAX) {
    return { ledger_accounts: {} };
  }

  const ah = input.account_holder;
  const prior = (ah && ah.recent_debits_24h) || [];

  const smurfPrior = prior.filter(function (t) {
    return typeof t.amount === 'number' && t.amount <= SMURF_MAX;
  });

  const totalCount = smurfPrior.length + 1;
  if (totalCount < SMURF_MIN_COUNT) return { ledger_accounts: {} };

  const total =
    smurfPrior.reduce(function (s, t) { return s + (t.amount || 0); }, 0) +
    txAmount;
  if (total <= SMURF_THRESHOLD_TOTAL) return { ledger_accounts: {} };

  const cps = new Set();
  for (const t of smurfPrior) {
    if (t.creditor_payment_account_id) cps.add(t.creditor_payment_account_id);
  }
  if (input.transaction && input.transaction.creditor_payment_account_id) {
    cps.add(input.transaction.creditor_payment_account_id);
  }
  if (cps.size < SMURF_MIN_DISTINCT_CP) return { ledger_accounts: {} };

  const debtor = input.debtor_payment_account;
  if (!debtor) return { ledger_accounts: {} };

  const las = debtor.las || [];
  const ledger_accounts = {};
  for (const la of las) {
    ledger_accounts[la.id] = {
      daily_debit_cap: 0,
      daily_credit_cap: 0,
      reason: 'smurfing_pattern_sar_eligible',
      block_reason: 'smurfing_pattern_sar_eligible',
      is_blocked: true
    };
  }
  return { ledger_accounts };
};
